-- Delete related Q&A questions
DELETE FROM live_qa_questions WHERE sessionId IN (SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false);

-- Delete transcript segments
DELETE FROM transcript_segments WHERE sessionId IN (SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false);

