DELETE FROM operator_actions WHERE sessionId IN (SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false);

-- Delete session handoff packages
DELETE FROM session_handoff_packages WHERE sessionId IN (SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false);

-- Delete session recordings
DELETE FROM session_recordings WHERE sessionId IN (SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false);

-- Delete operator sessions
DELETE FROM operator_sessions WHERE sessionId IN (SELECT sessionId FROM live_qa_session_metadata WHERE isLive = false);

-- Delete live QA session metadata (archived sessions)
DELETE FROM live_qa_session_metadata WHERE isLive = false;

